private struct SignalChatsScreen: View {
    @State private var selected: SignalChatThread? = nil
    private let threads = SignalDemoData.threads

    var body: some View {
        NavigationStack {
            List(threads) { thread in
                Button { selected = thread } label: {
                    SignalChatRow(thread: thread)
                }
                .buttonStyle(.plain)
                .listRowInsets(EdgeInsets(top: 8, leading: 16, bottom: 8, trailing: 16))
                .listRowSeparatorTint(SignalTokens.sigDivider.opacity(0.5))
            }
            .listStyle(.plain)
            .navigationTitle("Chats")
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {} label: { Image(systemName: "square.and.pencil") }
                }
            }
            .navigationDestination(item: $selected) { thread in
                SignalChatDetailScreen(thread: thread)
            }
        }
    }
}

private struct SignalChatRow: View {
    let thread: SignalChatThread
    var body: some View {
        HStack(spacing: 12) {
            Circle()
                .fill(thread.avatarColor.gradient)
                .frame(width: 48, height: 48)
                .overlay(Text(thread.initials).font(.system(size: 18, weight: .semibold)).foregroundStyle(.white))
                .overlay(Circle().strokeBorder(SignalTokens.sigBlue, lineWidth: thread.unread > 0 ? 2.5 : 0))
            VStack(alignment: .leading, spacing: 4) {
                HStack {
                    Text(thread.name).font(SignalFonts.sigMessageBody).foregroundStyle(SignalTokens.sigTextPrimary)
                    Spacer()
                    Text(thread.time).font(.system(size: 12)).foregroundStyle(SignalTokens.sigTextSecondary)
                }
                HStack {
                    Text(thread.preview).font(.system(size: 15)).foregroundStyle(SignalTokens.sigTextSecondary).lineLimit(1)
                    Spacer()
                    if thread.unread > 0 {
                        Text("\(thread.unread)").font(.system(size: 12, weight: .semibold)).foregroundStyle(.white)
                            .padding(.horizontal, 7).padding(.vertical, 3)
                            .background(Capsule().fill(SignalTokens.sigBlue))
                    }
                }
            }
        }
        .frame(height: 56)
    }
}

private struct SignalChatDetailScreen: View {
    let thread: SignalChatThread
    @State private var draft = ""
    var body: some View {
        VStack(spacing: 0) {
            ScrollView {
                VStack(spacing: 8) {
                    SignalSystemBanner(text: "Messages are end-to-end encrypted.")
                    ForEach(thread.messages) { msg in
                        if msg.outgoing {
                            SignalOutgoingBubble(text: msg.text, time: msg.time, accent: SignalTokens.sigCanvas, textColor: SignalTokens.sigTextPrimary, readColor: SignalTokens.sigBlue)
                        } else {
                            SignalIncomingBubble(text: msg.text, time: msg.time, fill: SignalTokens.sigIncoming, textColor: SignalTokens.sigTextPrimary)
                        }
                    }
                }
                .padding(.vertical, 12)
            }
            .background(SignalTokens.sigCanvas)
            SignalComposeBar(text: $draft, accent: SignalTokens.sigBlue)
        }
        .navigationTitle(thread.name)
        .navigationBarTitleDisplayMode(.inline)
    }
}

private struct SignalOutgoingBubble: View {
