    var body: some View {
        HStack {
            Spacer(minLength: 60)
            VStack(alignment: .trailing, spacing: 4) {
                Text(text).font(.system(size: 17)).foregroundStyle(textColor)
                HStack(spacing: 3) {
                    Text(time).font(.system(size: 11)).foregroundStyle(textColor.opacity(0.6))
                    Image(systemName: "checkmark").font(.system(size: 11, weight: .bold)).foregroundStyle(readColor)
                    Image(systemName: "checkmark").font(.system(size: 11, weight: .bold)).foregroundStyle(readColor).offset(x: -6)
                }
            }
            .padding(.vertical, 8).padding(.horizontal, 12)
            .background(UnevenRoundedRectangle(topLeadingRadius: 12, bottomLeadingRadius: 12, bottomTrailingRadius: 0, topTrailingRadius: 12).fill(accent))
        }
        .padding(.horizontal, 8)
    }
}

private struct SignalIncomingBubble: View {
