private struct SignalChatThread: Identifiable, Hashable {
    let id = UUID()
    let name: String
    let initials: String
    let preview: String
    let time: String
    let unread: Int
    let avatarColor: Color
    let messages: [SignalChatMessage]
}

private struct SignalChatMessage: Identifiable, Hashable {
    let id = UUID()
    let text: String
    let time: String
    let outgoing: Bool
}

